    item.enchantment !== undefined &&
    item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD
  ) {
    enchantmentSurcharge +=
      BASE_PREMIUMS[item.type] * HIGH_ENCHANTMENT_SURCHARGE_RATE;
